           (\n\
             source \"$z_f\"\n\
             zrbrn_kindle\n\
             zrbrn_enforce\n\
           )\n\
         done",
        buv.display(),
        rbk.display(), rbk.display(),
    );

    match rbtdrf_run_bash(&root, &script, dir, "rbrn-all-nameplates") {
        Ok((0, _, _)) => rbtdre_Verdict::Pass,
        Ok((code, _, _)) => {
            rbtdre_Verdict::Fail(format!("nameplate validation failed (exit {})", code))
        }
        Err(e) => rbtdre_Verdict::Fail(e),
    }
}

